sql:
SELECT COUNT(*) as total_reports, SUM(LENGTH(report_details)) as total_report_length
FROM case_reports
WHERE case_id = 1;

SELECT case_id AS id, 'M' AS gender FROM cases WHERE sesso = 'M'
UNION
SELECT demo_id AS id, 'M' AS gender FROM demographics WHERE gender = 'M';

SELECT * 
FROM cases 
WHERE case_id = 0;

SELECT age_group
FROM cases
WHERE case_id = 0;

SELECT age_group, MAX(comorbidities) AS max_comorbidities
FROM analytics
GROUP BY age_group;

SELECT status_name, description
FROM clinical_status
WHERE status_name = 'LIEVE';

SELECT AVG(julianday(case_updates.update_date) - julianday(cases.iss_date)) AS AverageDays
FROM cases
JOIN case_updates ON cases.case_id = case_updates.case_id;

SELECT COUNT(*)
FROM case_updates
WHERE new_status_id = 0;

SELECT COUNT(DISTINCT case_id) 
FROM cases 
WHERE test_result_date IS NOT NULL;

SELECT email 
FROM users 
WHERE role = 'researcher' AND department = 'Public Health';

SELECT users.user_name, users.email, users.role
FROM users
WHERE users.user_id IN (SELECT case_access.user_id FROM case_access);
